import { Heading3 } from "../atoms/Heading";
import classNames from "classnames";
import * as React from "react";
import { useInView } from "react-intersection-observer";

export default function Paragraph({
  title,
  extra = null,
  children,
  animationDelay = 0,
  asList = [],
  noAnimation = false,
}) {
  const { ref, inView } = useInView({
    threshold: 0.1, // Trigger when 10% of the element is visible
    triggerOnce: true,
  });

  const visible = inView || noAnimation;

  return (
    <div
      ref={ref}
      className={classNames(
        !visible && "lg:invisible",
        visible && "animate-ease-in-out lg:animate-fade-up",
      )}
      style={{ animationDelay: `${animationDelay}s` }}
    >
      <Heading3 className="mb-2">{title}</Heading3>

      {asList.length > 0 ? (
        <ul className="max-w-md space-y-1 list-disc list-inside">
          {asList.map((item, index) => (
            <li key={index}>{item}</li>
          ))}
        </ul>
      ) : (
        <p className="mb-4 text-gray-300 font-light">{children}</p>
      )}

      {extra}
    </div>
  );
}
