import Button from "../atoms/Button";
import { Heading2, Strong } from "../atoms/Heading";
import Input from "../atoms/Input";
import NeonText from "../atoms/NeonText";
import Container from "../molecules/Container";
import FootNote from "../molecules/Footnote";
import { faEnvelope } from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import classNames from "classnames";
import * as React from "react";
import { useInView } from "react-intersection-observer";

function AvailabilityMessage({
  available = true,
  availableMessage = "",
  notAvailableMessage = "",
}) {
  const { ref, inView } = useInView({
    threshold: 0.1, // Trigger when 10% of the element is visible
    triggerOnce: true,
  });

  return (
    <p
      ref={ref}
      className={classNames(
        "text-lg",

        !available && "text-red-600",
        available && "text-green-600",

        !inView && "lg:invisible",
        inView && "animate-ease-in-out lg:animate-fade-up",
      )}
    >
      <span
        className={classNames(
          "me-2 inline-block size-3 animate-pulse rounded-full",
          available && "bg-green-600",
          !available && "bg-red-600",
        )}
      />
      {available ? availableMessage : notAvailableMessage}
    </p>
  );
}

function Form() {
  const initialData = {
    name: "",
    email: "",
    message: "",
  };
  const [formData, setFormData] = React.useState(initialData);
  const [isSubmitting, setIsSubmitting] = React.useState(false);
  const [isSuccess, setIsSuccess] = React.useState(false);
  const [isError, setIsError] = React.useState(false);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };
  const handleSubmit = (event) => {
    event.preventDefault();

    setIsSuccess(false);
    setIsError(false);
    setIsSubmitting(true);

    const body = new FormData(event.target);
    body.append("access_key", "ed540b59-53c0-4868-ab5c-14789c5a9ffb");

    fetch("https://api.web3forms.com/submit", { method: "POST", body: body })
      .then((response) => response.json())
      .then((data) => {
        if (data.success) {
          setIsSuccess(true);
          setFormData(initialData);
        } else {
          setIsError(true);
          console.log("Error", data);
        }
      })
      .finally(() => setIsSubmitting(false));
  };

  return (
    <form className="mb-12" onSubmit={handleSubmit}>
      <Input
        name="name"
        placeholder="Votre nom complet"
        required
        value={formData.name}
        disabled={isSubmitting}
        onChange={handleChange}
      />
      <Input
        type="email"
        name="email"
        placeholder="Votre adresse e-mail"
        required
        disabled={isSubmitting}
        value={formData.email}
        onChange={handleChange}
      />
      <Input
        name="message"
        placeholder="Votre message…"
        multiline
        required
        disabled={isSubmitting}
        value={formData.message}
        onChange={handleChange}
      />

      <Button
        className="w-full"
        as="button"
        type="submit"
        disabled={isSubmitting}
      >
        {isSubmitting ? "Envoi en cours…" : "Envoyer le message"}
      </Button>

      <p className="mt-2.5 font-light text-center">
        {isSuccess && (
          <span className="text-green-600">Message envoyé avec succès !</span>
        )}
        {isError && (
          <span className="text-red-600">
            Une erreur est survenue. Veuillez réessayer plus tard.
          </span>
        )}
      </p>
    </form>
  );
}

