import { Heading1 } from "../atoms/Heading";
import classNames from "classnames";
import * as React from "react";

export default function Section({
  category,
  title,
  subtitle = null,
  extra = null,
  size = "1",
  children,
}) {
  return (
    <div className="mb-32 mt-8">
      <div className="mx-auto max-w-xl text-center lg:max-w-2xl">
        {category && (
          <span className="block mb-4 text-sm font-semibold tracking-widest text-jaune-fluo uppercase">
            {category}
          </span>
        )}
        <Heading1
          className={classNames(
            size === "1" && "mb-8 mt-4",
            size === "2" && "mb-6 mt-3",
          )}
          size={size === "1" ? "2" : "3"}
        >
          {title}
        </Heading1>

        <div className="mb-12">
          {subtitle && (
            <p className="text-gray-200 font-light text-lg xl:text-xl">
              {subtitle}
            </p>
          )}

          {extra}
        </div>
      </div>

      {children}
    </div>
  );
}
