const IndexPage = () => {
  const handleScroll = (event, targetId) => {
    event.preventDefault();
    const targetElement = document.getElementById(targetId);
    if (targetElement) {
      const navbarHeight = 86; // TODO: dynamic value
      const offset = 42; // Arbitrary
      window.scrollTo({
        top: targetElement.offsetTop - navbarHeight - offset,
        behavior: "smooth",
      });
    }
  };

  return (
    <>
      <Navbar
        navItems={navItems}
        socialItems={socialItems}
        onTitleClick={(e) => handleScroll(e, "hero")}
        onItemClick={(e, item) => handleScroll(e, item.targetId)}
      />

      <Container>
        <div id="hero">
          <Hero
            onFirstCtaClick={(e) => handleScroll(e, "about-my-work")}
            onSecondCtaClick={(e) => handleScroll(e, "projects")}
          />
        </div>
      </Container>

      <div id="about-my-work">
        <Container>
          <AboutMyWork />
        </Container>
      </div>

      <div id="experience">
        <Container>
          <MyExperience />
        </Container>
      </div>

      {/* <div id="projects">
        <Container>
          <MyProjects />
        </Container>
      </div> */}

      {/* <div id="freelanceServices">
        <Container>
          <MyFreelanceServices />
        </Container>
      </div> */}

      <div id="faq">
        <Container>
          <Faq questions={questions} />
        </Container>
      </div>

      <div id="contact">
        <ContactSection openToWork={openToWork} mailto={contactEmail} />
      </div>

      <Footer />
    </>
  );
};

