import classNames from "classnames";
import * as React from "react";

export function Strong({ tighter = false, children }) {
  return (
    <span
      className={classNames(
        "font-sans font-bold lg:tracking-tight",
        tighter && "xl:tracking-tighter",
      )}
    >
      {children}
    </span>
  );
}

export function Heading1({ className, size = "1", children }) {
  return (
    <h1
      className={classNames(
        "font-cursive",

        size === "1" && "text-5xl lg:text-6xl xl:text-7xl",
        size === "2" && "text-5xl xl:text-6xl",
        size === "3" && "text-4xl xl:text-5xl",

        className,
      )}
    >
      {children}
    </h1>
  );
}

export function Heading2({ className, children }) {
  return (
    <h2
      className={classNames(
        "font-cursive text-5xl",

        className,
      )}
    >
      {children}
    </h2>
  );
}

export function Heading3({ className, children }) {
  return (
    <h3
      className={classNames(
        "text-lg font-semibold uppercase tracking-widest",

        className,
      )}
    >
      {children}
    </h3>
  );
}
