import { faPlus } from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import classNames from "classnames";
import * as React from "react";
import { useRef } from "react";
import { useState } from "react";
import { useInView } from "react-intersection-observer";

function Item({ question, answer, isOpen, onOpen, animationDelay = 0 }) {
  const contentEl = useRef();

  const { ref, inView } = useInView({
    threshold: 0.1, // Trigger when 10% of the element is visible
    triggerOnce: true,
  });

  return (
    <li
      ref={ref}
      className={classNames(
        "border-b border-gray-900",

        !inView && "lg:invisible",
        inView && "animate-ease-in-out lg:animate-fade-up",
      )}
      style={{ animationDelay: `${animationDelay}s` }}
    >
      <button
        type="button"
        className="flex w-full items-center justify-between gap-4 text-lg lg:text-xl font-medium py-4 group"
        onClick={onOpen}
      >
        <h2
          className={classNames(
            "grow text-start transition-colors group-hover:text-white text-gray-400",

            isOpen && "text-white",
          )}
        >
          {question}
        </h2>
        <FontAwesomeIcon
          className={classNames(
            "size-4 flex-shrink-0 text-jaune-fluo",

            "transition-opacity",
            isOpen && "opacity-0",
          )}
          icon={faPlus}
        />
      </button>
      <div
        ref={contentEl}
        className={classNames(
          "overflow-hidden",
          "transition-all duration-500",

          !isOpen && "opacity-0",
          isOpen && "opacity-100",
        )}
        style={
          isOpen
            ? { height: contentEl.current.scrollHeight }
            : { height: "0px" }
        }
      >
        <div
          className={classNames(
            "-mt-2 pb-4 text-gray-400 mb-2 lg:text-lg font-light space-y-6",

            !isOpen && "pointer-events-none",
          )}
        >
          {answer}
        </div>
      </div>
    </li>
  );
}

export default function Accordion({ className, items = [] }) {
  const [openIndex, setOpenIndex] = useState(null);

  const handleToggle = (index) => {
    setOpenIndex(openIndex === index ? null : index);
  };

  return (
    <ol className={className}>
      {items.map((item, index) => (
        <Item
          key={index}
          question={item.question}
          answer={item.answer}
          isOpen={index === openIndex}
          onOpen={() => handleToggle(index)}
          animationDelay={0.1 * index}
        />
      ))}
    </ol>
  );
}
