import classNames from "classnames";
import * as React from "react";

const formatText = (text) => {
  let result = [];
  let lowerCaseGroup = "";
  const pushLowerCaseGroup = (group, key) => {
    result.push(
      <span className="text-[75%] font-bold" key={key}>
        {group}
      </span>,
    );
  };

  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    if (char.toLowerCase() === char && char.toUpperCase() !== char) {
      // Current character is lowercase
      lowerCaseGroup += char;
    } else {
      // Current character is uppercase or non-letter
      if (lowerCaseGroup) {
        // Add the group of lowercase letters wrapped in <span> if it exists
        pushLowerCaseGroup(lowerCaseGroup, `lowercase-${i}`);
        lowerCaseGroup = "";
      }
      result.push(char);
    }
  }

  // If there's any lowercase group left after the loop
  if (lowerCaseGroup) {
    pushLowerCaseGroup(lowerCaseGroup, "final-lowercase");
  }

  return result;
};

export default function PostIt({ className, text = "Lorem ipsum" }) {
  return (
    <span
      className={classNames(
        "relative inline-block aspect-square font-hand uppercase",
        className,
      )}
      aria-hidden="true"
    >
      {formatText(text)}
      <div
        className="absolute inset-0 -z-[1] rotate-1 overflow-hidden bg-jaune-fluo"
        style={{
          boxShadow:
            "inset 0 -40px 40px rgba(0, 0, 0, 0.2), inset 0 25px 10px rgba(0, 0, 0, 0.2), 0 5px 6px 5px rgba(0, 0, 0, 0.2)",
        }}
      />
    </span>
  );
}
