import classNames from "classnames";
import * as React from "react";

export default function Input({
  type = "text",
  name,
  placeholder = "",
  required = false,
  disabled = false,
  multiline = false,
  value,
  onChange,
}) {
  const commonClasses = classNames(
    "w-full px-4 py-3 border-2 placeholder:text-gray-400 rounded-md outline-none border-gray-600 focus:border-transparent bg-black mb-5 font-light",

    "focus:ring focus:ring-jaune-fluo",
    "disabled:text-gray-400 disabled:border-gray-800 disabled:cursor-not-allowed disabled:border-dotted",
  );

  if (multiline) {
    return (
      <textarea
        className={commonClasses}
        name={name}
        type={type}
        rows={7}
        placeholder={placeholder}
        lang="fr"
        required={required}
        disabled={disabled}
        value={value}
        onChange={onChange}
      />
    );
  }

  return (
    <input
      className={commonClasses}
      name={name}
      type={type}
      placeholder={placeholder}
      lang="fr"
      required={required}
      disabled={disabled}
      value={value}
      onChange={onChange}
    />
  );
}
