import useClickOutside from "../../hooks/useClickOutside";
import Button from "../atoms/Button";
import Link from "../atoms/Link";
import Container from "../molecules/Container";
import { faBars, faXmark } from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import classNames from "classnames";
import * as React from "react";
import { useState } from "react";
import { useRef } from "react";

export default function Navbar({
  navItems = [],
  socialItems = [],
  onTitleClick,
  onItemClick,
}) {
  const [isOpen, setIsOpen] = useState(false);

  const ref = useRef(null);
  useClickOutside(ref, () => setIsOpen(false));

  return (
    <div
      ref={ref}
      className="sticky top-0 z-10 animate-fade-down bg-black animate-ease-in-out"
    >
      <Container>
        <header className="flex flex-col items-center justify-between border-b-2 border-gray-700 py-5 lg:flex-row">
          <div className="flex w-full items-center justify-between lg:w-auto">
            <a
              className="cursor-pointer text-lg font-bold"
              href="/"
              onClick={onTitleClick}
            >
              Bryton Lacquement
            </a>
            <div className="block lg:hidden">
              <button
                aria-label="Toggle Menu"
                onClick={() => setIsOpen(!isOpen)}
              >
                <FontAwesomeIcon
                  icon={isOpen ? faXmark : faBars}
                  className="size-4"
                />
              </button>
            </div>
          </div>
          <nav
            className={classNames(
              "mt-2 w-full lg:mt-0 lg:flex lg:w-auto",
              !isOpen && "hidden",
            )}
          >
            <ul className="flex flex-col lg:flex-row lg:gap-3">
              {navItems.map((item, index) => (
                <li key={index}>
                  <a
                    className="flex cursor-pointer items-center gap-1 py-2 text-gray-300 hover:text-gray-400 lg:px-3"
                    href={`#${item.targetId}`}
                    onClick={(e) => onItemClick(e, item)}
                  >
                    <span>{item.label}</span>
                    {item.extra}
                  </a>
                </li>
              ))}
            </ul>
            <div className="mt-3 flex items-center justify-between gap-4 lg:hidden">
              {socialItems.map((social, index) => {
                if (!["fill", "not fill"].includes(social.buttonFlavor)) {
                  return;
                }

                return (
                  <Button
                    key={index}
                    href={social.url}
                    size="sm"
                    className="w-full"
                    fill={social.buttonFlavor === "fill"}
                  >
                    {social.name}
                  </Button>
                );
              })}
            </div>
          </nav>
          <div>
            <div className="hidden items-center justify-center gap-4 py-1.5 lg:flex">
              {socialItems.map((social, index) => (
                <Link key={index} href={social.url} faIcon={social.faIcon} />
              ))}
            </div>
          </div>
        </header>
      </Container>
    </div>
  );
}
