import { format, formatDistance } from "date-fns";
import { fr } from "date-fns/locale";
import * as React from "react";

function createDate(isoString) {
  return new Date(isoString + "T00:00:00.000Z");
}

function renderDateString(dateStart, dateEnd = null) {
  return (
    <>
      {format(dateStart, "MMM yyyy", { locale: fr })} -{" "}
      {dateEnd ? (
        <>
          {format(dateEnd, "MMM yyyy", { locale: fr })} ·{" "}
          {formatDistance(dateStart, dateEnd, {
            locale: fr,
          })}
        </>
      ) : (
        "aujourd'hui"
      )}
    </>
  );
}

